-- 006_prelaunch_status.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Site-wide settings (key/value)
CREATE TABLE IF NOT EXISTS site_settings (
  key TEXT PRIMARY KEY,
  value TEXT NOT NULL,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Seed defaults
INSERT INTO site_settings (key, value) VALUES
  ('prelaunch_cleaner', 'true'),
  ('prelaunch_customer', 'true')
ON CONFLICT (key) DO NOTHING;

-- Status incidents
CREATE TABLE IF NOT EXISTS status_incidents (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL,
  summary TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'investigating'
    CHECK (status IN ('investigating','identified','monitoring','resolved')),
  severity TEXT NOT NULL DEFAULT 'minor'
    CHECK (severity IN ('minor','major','critical')),
  affected_features TEXT[] NOT NULL DEFAULT '{}',
  is_prelaunch_update BOOLEAN NOT NULL DEFAULT FALSE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  resolved_at TIMESTAMPTZ
);

-- Per-incident timeline updates
CREATE TABLE IF NOT EXISTS status_updates (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  incident_id UUID NOT NULL REFERENCES status_incidents(id) ON DELETE CASCADE,
  message TEXT NOT NULL,
  status TEXT NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Newsletter subscribers
CREATE TABLE IF NOT EXISTS newsletter_subscribers (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email TEXT UNIQUE NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Status incident subscribers (per-incident email alerts)
CREATE TABLE IF NOT EXISTS status_subscribers (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email TEXT NOT NULL,
  incident_id UUID NOT NULL REFERENCES status_incidents(id) ON DELETE CASCADE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE(email, incident_id)
);

-- Waitlist (cleaners + customers)
CREATE TABLE IF NOT EXISTS waitlist (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email TEXT NOT NULL,
  name TEXT,
  phone TEXT,
  zip_code TEXT,
  type TEXT NOT NULL CHECK (type IN ('cleaner','customer')),
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ─────────────────────────────────────────────────────────────────────────
-- 007_training_system.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Training modules (base + service-specific)
CREATE TABLE IF NOT EXISTS training_modules (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  title TEXT NOT NULL,
  description TEXT,
  category TEXT,
  required_type TEXT NOT NULL CHECK (required_type IN ('base', 'service_specific', 'optional')),
  service_key TEXT,
  estimated_minutes INT,
  active BOOL DEFAULT true,
  version INT DEFAULT 1,
  sort_order INT DEFAULT 0,
  requires_quiz BOOL DEFAULT true,
  passing_score INT DEFAULT 80,
  max_attempts INT DEFAULT 3,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Lessons within a module
CREATE TABLE IF NOT EXISTS training_lessons (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  module_id UUID NOT NULL REFERENCES training_modules(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  body TEXT NOT NULL,
  video_url TEXT,
  image_url TEXT,
  sort_order INT DEFAULT 0,
  estimated_minutes INT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Quiz questions for a module
CREATE TABLE IF NOT EXISTS training_quiz_questions (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  module_id UUID NOT NULL REFERENCES training_modules(id) ON DELETE CASCADE,
  question TEXT NOT NULL,
  type TEXT NOT NULL DEFAULT 'multiple_choice',
  choices JSONB NOT NULL DEFAULT '[]',
  correct_answer TEXT NOT NULL,
  explanation TEXT,
  sort_order INT DEFAULT 0
);

-- Cleaner progress per module
CREATE TABLE IF NOT EXISTS cleaner_training_progress (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  cleaner_id UUID NOT NULL REFERENCES cleaners(id) ON DELETE CASCADE,
  module_id UUID NOT NULL REFERENCES training_modules(id) ON DELETE CASCADE,
  module_version INT DEFAULT 1,
  status TEXT NOT NULL DEFAULT 'not_started' CHECK (status IN ('not_started', 'in_progress', 'passed', 'failed', 'review_required')),
  started_at TIMESTAMPTZ,
  completed_at TIMESTAMPTZ,
  last_lesson_id UUID REFERENCES training_lessons(id),
  score INT,
  attempt_count INT DEFAULT 0,
  required_for_activation BOOL DEFAULT true,
  UNIQUE(cleaner_id, module_id)
);

-- Individual quiz attempt records
CREATE TABLE IF NOT EXISTS cleaner_quiz_attempts (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  cleaner_id UUID NOT NULL REFERENCES cleaners(id) ON DELETE CASCADE,
  module_id UUID NOT NULL REFERENCES training_modules(id) ON DELETE CASCADE,
  score INT,
  passed BOOL,
  answers JSONB,
  started_at TIMESTAMPTZ DEFAULT NOW(),
  completed_at TIMESTAMPTZ
);

-- Indexes
CREATE INDEX IF NOT EXISTS idx_training_lessons_module ON training_lessons(module_id, sort_order);
CREATE INDEX IF NOT EXISTS idx_training_quiz_questions_module ON training_quiz_questions(module_id, sort_order);
CREATE INDEX IF NOT EXISTS idx_cleaner_training_progress_cleaner ON cleaner_training_progress(cleaner_id);
CREATE INDEX IF NOT EXISTS idx_cleaner_quiz_attempts_cleaner ON cleaner_quiz_attempts(cleaner_id, module_id);

-- Add training columns to cleaners
ALTER TABLE cleaners ADD COLUMN IF NOT EXISTS training_status TEXT DEFAULT 'not_started';
ALTER TABLE cleaners ADD COLUMN IF NOT EXISTS training_completed_at TIMESTAMPTZ;
ALTER TABLE cleaners ADD COLUMN IF NOT EXISTS required_training_completed BOOL DEFAULT false;
ALTER TABLE cleaners ADD COLUMN IF NOT EXISTS background_check_unlocked BOOL DEFAULT false;

-- Drop old status constraint and add comprehensive one
ALTER TABLE cleaners DROP CONSTRAINT IF EXISTS cleaners_status_check;
DO $$ BEGIN
  ALTER TABLE cleaners ADD CONSTRAINT cleaners_status_check CHECK (status IN (
  'draft',
  'profile_incomplete',
  'identity_pending',
  'training_required',
  'training_in_progress',
  'training_failed',
  'training_completed',
  'background_check_available',
  'background_check_pending',
  'background_check_passed',
  'background_check_failed',
  'pending_activation',
  'active',
  'paused',
  'rejected',
  -- legacy values kept for backward compat during migration
  'pending',
  'approved',
  'suspended'
));
EXCEPTION WHEN duplicate_object THEN NULL; WHEN duplicate_table THEN NULL;
END $$;

-- ─────────────────────────────────────────────────────────────────────────
-- 009_admin_invites_device_tokens.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Admin invite tokens — one-time signed URLs for granting admin access.
-- The first admin is created by running:
--   UPDATE users SET role = 'admin' WHERE email = '<your-email>';
-- in the Neon SQL editor. Subsequent admins are invited from the console.

CREATE TABLE IF NOT EXISTS admin_invites (
  id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  token       TEXT        NOT NULL UNIQUE,
  email       TEXT        NOT NULL,
  created_by  TEXT        NOT NULL,       -- clerk_id of inviting admin
  used_at     TIMESTAMPTZ,
  expires_at  TIMESTAMPTZ NOT NULL DEFAULT NOW() + INTERVAL '7 days',
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS admin_invites_token_idx ON admin_invites(token);

-- FCM device tokens for push notifications (mobile app).
-- One user can have multiple devices; each device has one token.
CREATE TABLE IF NOT EXISTS device_tokens (
  id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id     UUID        NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  token       TEXT        NOT NULL,
  platform    TEXT        NOT NULL DEFAULT 'fcm',   -- 'fcm' | 'apns'
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE(user_id, token)
);
CREATE INDEX IF NOT EXISTS device_tokens_user_idx ON device_tokens(user_id);

-- ─────────────────────────────────────────────────────────────────────────
-- 010_service_areas.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Confirmed service areas (live + upcoming) with GeoJSON polygon for map display
CREATE TABLE IF NOT EXISTS service_areas (
  id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  name        TEXT        NOT NULL,
  slug        TEXT        NOT NULL UNIQUE,
  status      TEXT        NOT NULL DEFAULT 'upcoming' CHECK (status IN ('live', 'upcoming')),
  -- GeoJSON polygon as [[lng,lat],...] stored as JSONB
  polygon     JSONB,
  center_lat  DOUBLE PRECISION,
  center_lng  DOUBLE PRECISION,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Seed Bay Area as the first live market
INSERT INTO service_areas (name, slug, status, center_lat, center_lng, polygon) VALUES (
  'Bay Area', 'bay-area', 'live', 37.7749, -122.4194,
  '[ [-122.608,37.907],[-122.271,38.103],[-121.997,38.047],[-121.560,37.981],[-121.483,37.650],[-121.573,37.348],[-121.748,37.183],[-122.001,37.047],[-122.379,37.093],[-122.472,37.283],[-122.513,37.475],[-122.510,37.707],[-122.608,37.907] ]'
) ON CONFLICT (slug) DO NOTHING;

-- City requests — one row per submission (includes optional lat/lng from client geocoding)
CREATE TABLE IF NOT EXISTS city_requests (
  id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  input       TEXT        NOT NULL,   -- raw text the user typed
  lat         DOUBLE PRECISION,
  lng         DOUBLE PRECISION,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS city_requests_created_idx ON city_requests(created_at DESC);

-- City update subscribers — separate from newsletter and waitlist
-- area_slug NULL means "any city / notify me when you expand"
CREATE TABLE IF NOT EXISTS city_subscribers (
  id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  email       TEXT        NOT NULL,
  area_slug   TEXT,
  city_input  TEXT,                   -- what they typed when subscribing
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
-- Expression-based unique index (inline UNIQUE with COALESCE is not valid PostgreSQL syntax)
CREATE UNIQUE INDEX IF NOT EXISTS city_subscribers_email_slug_idx
  ON city_subscribers(email, COALESCE(area_slug, ''));
CREATE INDEX IF NOT EXISTS city_subscribers_slug_idx ON city_subscribers(area_slug);

-- Broadcast history — one row per send (all list types)
CREATE TABLE IF NOT EXISTS broadcast_sends (
  id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  audience    TEXT        NOT NULL,   -- 'newsletter'|'waitlist_customer'|'waitlist_cleaner'|'city'|'all'
  area_slug   TEXT,                   -- set when audience='city'
  subject     TEXT        NOT NULL,
  html        TEXT        NOT NULL,
  sent_count  INTEGER     NOT NULL DEFAULT 0,
  sent_by     TEXT        NOT NULL,   -- clerk_id
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ─────────────────────────────────────────────────────────────────────────
-- 011_course_builder.sql
-- ─────────────────────────────────────────────────────────────────────────
-- ============================================================================
-- Course Builder (next-generation, PowerPoint-style training authoring)
--
-- This is a NEW system that lives alongside the existing module-based training
-- library (007_training_system.sql). The old training_modules/lessons/quizzes
-- remain the certification of record until a course here is published to
-- replace them. Nothing in this migration touches the existing tables.
--
-- Hierarchy:  courses → course_versions → course_slides → slide_blocks
--             (quiz blocks) → course_quiz_questions → course_quiz_answers
--             learner progress: user_course_progress → user_slide_progress
-- ============================================================================

-- Master course record (mutable metadata; content lives in versions).
CREATE TABLE IF NOT EXISTS courses (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  title TEXT NOT NULL,
  description TEXT,
  category TEXT,
  status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft', 'published', 'archived')),
  required BOOLEAN DEFAULT true,
  -- Optional link to a legacy module this course is intended to replace.
  replaces_module_id UUID REFERENCES training_modules(id) ON DELETE SET NULL,
  current_version_id UUID,
  created_by TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- A version is a snapshot of course content. Drafts are editable; once
-- published they are immutable and learners are bound to a specific version.
CREATE TABLE IF NOT EXISTS course_versions (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  course_id UUID NOT NULL REFERENCES courses(id) ON DELETE CASCADE,
  version_number INTEGER NOT NULL,
  status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft', 'published', 'archived')),
  require_retake BOOLEAN DEFAULT false,
  published_at TIMESTAMPTZ,
  published_by TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE (course_id, version_number)
);

-- Slides belong to a version.
CREATE TABLE IF NOT EXISTS course_slides (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  course_version_id UUID NOT NULL REFERENCES course_versions(id) ON DELETE CASCADE,
  title TEXT,
  slide_type TEXT DEFAULT 'content',
  slide_order INTEGER NOT NULL DEFAULT 0,
  background JSONB DEFAULT '{}'::jsonb,
  completion_rule JSONB DEFAULT '{"type":"viewed"}'::jsonb,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Blocks are positioned PowerPoint-style objects on a slide.
CREATE TABLE IF NOT EXISTS slide_blocks (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  slide_id UUID NOT NULL REFERENCES course_slides(id) ON DELETE CASCADE,
  block_type TEXT NOT NULL CHECK (block_type IN (
    'text', 'image', 'video', 'quiz', 'button', 'checklist', 'acknowledgment'
  )),
  x NUMERIC NOT NULL DEFAULT 8,
  y NUMERIC NOT NULL DEFAULT 8,
  width NUMERIC NOT NULL DEFAULT 84,
  height NUMERIC NOT NULL DEFAULT 20,
  z_index INTEGER NOT NULL DEFAULT 0,
  props JSONB NOT NULL DEFAULT '{}'::jsonb
);

-- Quiz questions belong to a quiz block.
CREATE TABLE IF NOT EXISTS course_quiz_questions (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  block_id UUID NOT NULL REFERENCES slide_blocks(id) ON DELETE CASCADE,
  question_text TEXT NOT NULL,
  question_type TEXT NOT NULL DEFAULT 'multiple_choice' CHECK (question_type IN (
    'multiple_choice', 'multi_select', 'true_false', 'image_choice', 'short_answer'
  )),
  required BOOLEAN DEFAULT true,
  points INTEGER DEFAULT 1,
  sort_order INTEGER DEFAULT 0
);

CREATE TABLE IF NOT EXISTS course_quiz_answers (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  question_id UUID NOT NULL REFERENCES course_quiz_questions(id) ON DELETE CASCADE,
  answer_text TEXT NOT NULL,
  is_correct BOOLEAN DEFAULT false,
  sort_order INTEGER DEFAULT 0
);

-- Learner progress, bound to a specific published version.
CREATE TABLE IF NOT EXISTS user_course_progress (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id TEXT NOT NULL,
  course_version_id UUID NOT NULL REFERENCES course_versions(id) ON DELETE CASCADE,
  status TEXT NOT NULL DEFAULT 'in_progress' CHECK (status IN ('in_progress', 'completed', 'failed')),
  progress_percent INTEGER DEFAULT 0,
  started_at TIMESTAMPTZ DEFAULT now(),
  completed_at TIMESTAMPTZ,
  UNIQUE (user_id, course_version_id)
);

CREATE TABLE IF NOT EXISTS user_slide_progress (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_progress_id UUID NOT NULL REFERENCES user_course_progress(id) ON DELETE CASCADE,
  slide_id UUID NOT NULL REFERENCES course_slides(id) ON DELETE CASCADE,
  viewed BOOLEAN DEFAULT false,
  completed BOOLEAN DEFAULT false,
  seconds_spent INTEGER DEFAULT 0,
  UNIQUE (user_progress_id, slide_id)
);

-- FK from courses.current_version_id added after course_versions exists.
ALTER TABLE courses
  DROP CONSTRAINT IF EXISTS courses_current_version_fk;
DO $$ BEGIN
  ALTER TABLE courses ADD CONSTRAINT courses_current_version_fk FOREIGN KEY (current_version_id) REFERENCES course_versions(id) ON DELETE SET NULL;
EXCEPTION WHEN duplicate_object THEN NULL; WHEN duplicate_table THEN NULL;
END $$;

-- Indexes
CREATE INDEX IF NOT EXISTS idx_course_versions_course ON course_versions(course_id, version_number);
CREATE INDEX IF NOT EXISTS idx_course_slides_version ON course_slides(course_version_id, slide_order);
CREATE INDEX IF NOT EXISTS idx_slide_blocks_slide ON slide_blocks(slide_id, z_index);
CREATE INDEX IF NOT EXISTS idx_course_quiz_questions_block ON course_quiz_questions(block_id, sort_order);
CREATE INDEX IF NOT EXISTS idx_course_quiz_answers_question ON course_quiz_answers(question_id, sort_order);
CREATE INDEX IF NOT EXISTS idx_user_course_progress_user ON user_course_progress(user_id);
CREATE INDEX IF NOT EXISTS idx_user_slide_progress_progress ON user_slide_progress(user_progress_id);

-- ─────────────────────────────────────────────────────────────────────────
-- 012_day_of_service.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Day-of-service operational flow
-- Extends bookings with real-time tracking, photo evidence, GPS verification,
-- and secure access code delivery.

-- ── Status substates ─────────────────────────────────────────────────────────
-- The canonical booking status progression:
--   scheduled → en_route → arrived → in_progress → awaiting_checkout → completed
-- Legacy statuses (draft, matching, confirmed, disputed, cancelled_*) remain.

ALTER TABLE bookings
  ADD COLUMN IF NOT EXISTS day_status TEXT,            -- null = not yet day-of
  ADD COLUMN IF NOT EXISTS cleaner_lat NUMERIC(10,7),  -- GPS on "Start Route"
  ADD COLUMN IF NOT EXISTS cleaner_lng NUMERIC(10,7),
  ADD COLUMN IF NOT EXISTS arrival_verified_at TIMESTAMPTZ, -- GPS proximity confirmed
  ADD COLUMN IF NOT EXISTS started_at TIMESTAMPTZ,          -- "Start Clean" tapped
  ADD COLUMN IF NOT EXISTS completed_at TIMESTAMPTZ,        -- "Finish Clean" tapped
  ADD COLUMN IF NOT EXISTS address_revealed_at TIMESTAMPTZ, -- when full address was sent
  ADD COLUMN IF NOT EXISTS access_code_revealed_at TIMESTAMPTZ; -- when access code was sent

-- ── Before/after photo evidence ───────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS booking_photos (
  id           UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  booking_id   UUID NOT NULL REFERENCES bookings(id) ON DELETE CASCADE,
  photo_type   TEXT NOT NULL CHECK (photo_type IN ('before','after','checkout','damage')),
  storage_key  TEXT NOT NULL,  -- R2 object key (never a public URL)
  room_label   TEXT,           -- "kitchen", "bathroom_1", "bedroom_2", etc.
  uploaded_by  TEXT NOT NULL,  -- clerk_id of uploader
  created_at   TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_booking_photos_booking ON booking_photos(booking_id);
CREATE INDEX IF NOT EXISTS idx_booking_photos_type    ON booking_photos(booking_id, photo_type);

-- ── Real-time location pings from cleaner ─────────────────────────────────────
-- Retained for 72 hours then purged (privacy: §3.3 handbook).
CREATE TABLE IF NOT EXISTS cleaner_location_pings (
  id          UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  booking_id  UUID NOT NULL REFERENCES bookings(id) ON DELETE CASCADE,
  cleaner_id  UUID NOT NULL REFERENCES cleaners(id) ON DELETE CASCADE,
  lat         NUMERIC(10,7) NOT NULL,
  lng         NUMERIC(10,7) NOT NULL,
  accuracy_m  NUMERIC(6,1),
  heading     NUMERIC(5,1),
  speed_kmh   NUMERIC(5,1),
  created_at  TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_location_pings_booking  ON cleaner_location_pings(booking_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_location_pings_created  ON cleaner_location_pings(created_at);

-- ── Completion package ────────────────────────────────────────────────────────
-- Snapshot generated when a job completes; immutable audit record.
CREATE TABLE IF NOT EXISTS job_completion_packages (
  id             UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  booking_id     UUID NOT NULL UNIQUE REFERENCES bookings(id) ON DELETE CASCADE,
  cleaner_id     UUID REFERENCES cleaners(id),
  customer_id    UUID REFERENCES customers(id),
  started_at     TIMESTAMPTZ,
  completed_at   TIMESTAMPTZ,
  duration_mins  INT,
  before_photo_count INT DEFAULT 0,
  after_photo_count  INT DEFAULT 0,
  checkout_photo_key TEXT,      -- checkout photo storage key
  summary_json   JSONB,         -- full snapshot of job details at completion
  created_at     TIMESTAMPTZ DEFAULT NOW()
);

-- ── Secure access codes ───────────────────────────────────────────────────────
-- Stored encrypted at rest; delivered only after GPS arrival verification.
-- The cleaner app never receives these until the system confirms proximity.
CREATE TABLE IF NOT EXISTS booking_access_codes (
  id          UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  booking_id  UUID NOT NULL UNIQUE REFERENCES bookings(id) ON DELETE CASCADE,
  code_type   TEXT NOT NULL CHECK (code_type IN ('lockbox','keypad','doorcode','building','garage','other')),
  code_value  TEXT NOT NULL,  -- application-level encrypted; decrypt in API only
  notes       TEXT,
  created_by  TEXT NOT NULL,  -- clerk_id of customer who entered it
  created_at  TIMESTAMPTZ DEFAULT NOW(),
  updated_at  TIMESTAMPTZ DEFAULT NOW()
);

-- ─────────────────────────────────────────────────────────────────────────
-- 013_insurance.sql
-- ─────────────────────────────────────────────────────────────────────────
-- 013_insurance.sql
-- Cleaner insurance module: Sweepr Coverage Program vs personal policy upload

DO $$ BEGIN
  CREATE TYPE insurance_coverage_type AS ENUM ('sweepr_program', 'personal_policy');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;
DO $$ BEGIN
  CREATE TYPE insurance_policy_status AS ENUM (
  'pending_upload',   -- cleaner hasn't uploaded anything yet
  'pending_review',   -- document uploaded, awaiting admin review
  'active',           -- approved and not expired
  'expiring_soon',    -- within 30 days of expiry
  'expired',          -- past expiry date
  'rejected'          -- admin rejected the document
);
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

CREATE TABLE IF NOT EXISTS cleaner_insurance (
  id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  cleaner_id          UUID NOT NULL REFERENCES cleaners(id) ON DELETE CASCADE,

  coverage_type       insurance_coverage_type NOT NULL DEFAULT 'sweepr_program',

  -- Sweepr Coverage Program (Stripe subscription)
  stripe_subscription_id TEXT,
  program_active_since   TIMESTAMPTZ,
  program_cancelled_at   TIMESTAMPTZ,

  -- Personal policy fields (cleaner uploads their own COI / declarations page)
  policy_status       insurance_policy_status NOT NULL DEFAULT 'pending_upload',
  policy_number       TEXT,
  insurer_name        TEXT,
  coverage_amount_usd INTEGER,         -- e.g. 1000000 for $1M
  policy_expires_at   TIMESTAMPTZ,
  doc_storage_key     TEXT,            -- R2 key of the uploaded PDF/image
  doc_uploaded_at     TIMESTAMPTZ,
  review_notes        TEXT,            -- admin rejection reason or approval note
  reviewed_by         TEXT,            -- admin clerk_id
  reviewed_at         TIMESTAMPTZ,

  created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),

  UNIQUE (cleaner_id)
);

-- Audit trail for status changes
CREATE TABLE IF NOT EXISTS insurance_status_log (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  cleaner_id    UUID NOT NULL REFERENCES cleaners(id) ON DELETE CASCADE,
  previous_status insurance_policy_status,
  new_status      insurance_policy_status NOT NULL,
  changed_by      TEXT,  -- clerk_id of actor (admin or system)
  note            TEXT,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Index for expiry-check cron jobs
CREATE INDEX IF NOT EXISTS idx_cleaner_insurance_expires
  ON cleaner_insurance (policy_expires_at)
  WHERE policy_status IN ('active', 'expiring_soon');

-- Auto-update updated_at
CREATE OR REPLACE FUNCTION set_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_trigger WHERE tgname = 'cleaner_insurance_updated_at'
  ) THEN
    CREATE TRIGGER cleaner_insurance_updated_at
      BEFORE UPDATE ON cleaner_insurance
      FOR EACH ROW EXECUTE FUNCTION set_updated_at();
  END IF;
END;
$$;

-- ─────────────────────────────────────────────────────────────────────────
-- 014_schema_alignment.sql
-- ─────────────────────────────────────────────────────────────────────────
-- 014_schema_alignment.sql
-- Aligns the live DB with columns the API code references.
-- Idempotent — safe to run multiple times.
--
-- Root cause of the "no data in admin dashboard" bug: the admin queries
-- referenced columns that never existed in the schema, so every admin
-- endpoint threw and the console rendered empty.

-- Cleaner location (admin console + day-of-service display).
ALTER TABLE cleaners ADD COLUMN IF NOT EXISTS city  TEXT;
ALTER TABLE cleaners ADD COLUMN IF NOT EXISTS state TEXT;

-- Stripe Connect onboarding status surfaced in the admin cleaners table.
-- One of: 'not_started' | 'pending' | 'active' | 'restricted' | 'rejected'
ALTER TABLE cleaners ADD COLUMN IF NOT EXISTS stripe_connect_status TEXT DEFAULT 'not_started';

-- Backfill a sensible status from existing connect IDs.
UPDATE cleaners
   SET stripe_connect_status = 'pending'
 WHERE stripe_connect_id IS NOT NULL
   AND (stripe_connect_status IS NULL OR stripe_connect_status = 'not_started');

-- The payments table stores cents in `amount`. Some code referenced
-- `amount_cents`; rather than duplicate the column we keep `amount` as the
-- single source of truth (the API has been corrected to match). This block
-- only runs if a stray `amount_cents` column was created by hand — it folds
-- the data back into `amount` and drops the duplicate.
DO $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'payments' AND column_name = 'amount_cents'
  ) THEN
    UPDATE payments SET amount = COALESCE(amount, amount_cents) WHERE amount IS NULL;
    ALTER TABLE payments DROP COLUMN amount_cents;
  END IF;
END $$;

-- Helpful indexes for the admin dashboard aggregations.
CREATE INDEX IF NOT EXISTS idx_payments_status ON payments(status);
CREATE INDEX IF NOT EXISTS idx_payments_created_at ON payments(created_at);
CREATE INDEX IF NOT EXISTS idx_cleaners_status ON cleaners(status);
CREATE INDEX IF NOT EXISTS idx_disputes_status ON disputes(status);

-- ─────────────────────────────────────────────────────────────────────────
-- 015_course_block_types.sql
-- ─────────────────────────────────────────────────────────────────────────
-- 015_course_block_types.sql
-- Widen the slide_blocks.block_type CHECK to support the richer, PowerPoint-style
-- course editor (headings, shapes, dividers, callouts, spacers).
-- Idempotent.

ALTER TABLE slide_blocks DROP CONSTRAINT IF EXISTS slide_blocks_block_type_check;

DO $$ BEGIN
  ALTER TABLE slide_blocks ADD CONSTRAINT slide_blocks_block_type_check CHECK (block_type IN (
    -- content
    'text', 'heading', 'image', 'video', 'embed',
    -- layout / decoration
    'shape', 'divider', 'spacer', 'callout',
    -- interactive / course-specific
    'quiz', 'button', 'checklist', 'acknowledgment'
  ));
EXCEPTION WHEN duplicate_object THEN NULL; WHEN duplicate_table THEN NULL;
END $$;

