    CHECK (category IN ('bug','billing','account','technical','feature_request','safety','other')),
  priority       TEXT NOT NULL DEFAULT 'normal'
    CHECK (priority IN ('low','normal','high','urgent')),
  status         TEXT NOT NULL DEFAULT 'open'
    CHECK (status IN ('open','in_progress','resolved','closed')),
  source         TEXT NOT NULL DEFAULT 'user_report'
    CHECK (source IN ('user_report','error','admin')),
  app            TEXT,                         -- customer | cleaner | admin | api | service
  reporter_clerk_id TEXT,
  reporter_email TEXT,
  assigned_to    TEXT,                          -- admin clerk id
  related_error_id UUID REFERENCES error_logs(id) ON DELETE SET NULL,
  context        JSONB NOT NULL DEFAULT '{}',
  due_at         TIMESTAMPTZ,
  resolved_at    TIMESTAMPTZ,
  closed_at      TIMESTAMPTZ,
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_it_tickets_status   ON it_tickets (status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_it_tickets_due      ON it_tickets (due_at) WHERE status IN ('open','in_progress');
CREATE INDEX IF NOT EXISTS idx_it_tickets_reporter ON it_tickets (reporter_clerk_id);

CREATE TABLE IF NOT EXISTS it_ticket_comments (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  ticket_id   UUID NOT NULL REFERENCES it_tickets(id) ON DELETE CASCADE,
  author_clerk_id TEXT,
  author_email TEXT,
  is_admin    BOOLEAN NOT NULL DEFAULT FALSE,
  body        TEXT NOT NULL,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_it_ticket_comments_ticket ON it_ticket_comments (ticket_id, created_at);

-- ── Notification settings ────────────────────────────────────────────────────
-- One row per notification event key. The full catalog of available events lives
-- in code; this table stores the admin on/off override per event.
CREATE TABLE IF NOT EXISTS notification_settings (
  event_key   TEXT PRIMARY KEY,
  enabled     BOOLEAN NOT NULL DEFAULT TRUE,
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_by  TEXT
);

-- ── Add the "it" admin role to the existing CHECK constraints ─────────────────
ALTER TABLE users DROP CONSTRAINT IF EXISTS users_admin_role_check;
DO $$ BEGIN
  ALTER TABLE users ADD CONSTRAINT users_admin_role_check CHECK (admin_role IN ('super_admin','admin','ops','finance','trainer','support','it'));
EXCEPTION WHEN duplicate_object THEN NULL; WHEN duplicate_table THEN NULL;
END $$;

ALTER TABLE admin_invites DROP CONSTRAINT IF EXISTS admin_invites_admin_role_check;
DO $$ BEGIN
  ALTER TABLE admin_invites ADD CONSTRAINT admin_invites_admin_role_check CHECK (admin_role IN ('super_admin','admin','ops','finance','trainer','support','it'));
EXCEPTION WHEN duplicate_object THEN NULL; WHEN duplicate_table THEN NULL;
END $$;

-- ─────────────────────────────────────────────────────────────────────────
-- 031_hard_delete_cascades.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Migration 031: make the database genuinely hard-deletable for GDPR/CCPA.
--
-- Recreates the key foreign keys with ON DELETE CASCADE so deleting a user row
-- actually removes all of their data (no orphans, no FK-restrict failures).
-- Also adds a non-PII deletion audit log so we can prove a deletion happened
-- without retaining any personal data.

-- Helper: drop whatever FK exists on (table, single column) and re-add it with
-- ON DELETE CASCADE pointing at <ref>(id). Idempotent / safe to re-run.
CREATE OR REPLACE FUNCTION _recreate_fk_cascade(p_table regclass, p_column text, p_ref regclass)
RETURNS void AS $$
DECLARE cname text;
BEGIN
  IF to_regclass(p_table::text) IS NULL OR to_regclass(p_ref::text) IS NULL THEN RETURN; END IF;
  SELECT conname INTO cname
  FROM pg_constraint
  WHERE contype = 'f' AND conrelid = p_table
    AND conkey = (SELECT array_agg(attnum)
                  FROM pg_attribute
                  WHERE attrelid = p_table AND attname = p_column AND NOT attisdropped);
  IF cname IS NOT NULL THEN
    EXECUTE format('ALTER TABLE %s DROP CONSTRAINT %I', p_table, cname);
  END IF;
  EXECUTE format(
    'ALTER TABLE %s ADD FOREIGN KEY (%I) REFERENCES %s(id) ON DELETE CASCADE',
    p_table, p_column, p_ref
  );
EXCEPTION WHEN undefined_column OR undefined_table THEN
  RETURN; -- table/column not present on this DB — skip
END$$ LANGUAGE plpgsql;

DO $$
BEGIN
  -- Direct children of users
  PERFORM _recreate_fk_cascade('customers', 'user_id', 'users');
  PERFORM _recreate_fk_cascade('cleaners', 'user_id', 'users');
  PERFORM _recreate_fk_cascade('addresses', 'user_id', 'users');
  PERFORM _recreate_fk_cascade('notifications', 'user_id', 'users');
  PERFORM _recreate_fk_cascade('data_subject_requests', 'user_id', 'users');
  PERFORM _recreate_fk_cascade('consent_log', 'user_id', 'users');
  PERFORM _recreate_fk_cascade('device_tokens', 'user_id', 'users');

  -- Bookings + their dependents
  PERFORM _recreate_fk_cascade('bookings', 'customer_id', 'customers');
  PERFORM _recreate_fk_cascade('bookings', 'cleaner_id', 'cleaners');
  PERFORM _recreate_fk_cascade('bookings', 'address_id', 'addresses');
  PERFORM _recreate_fk_cascade('payments', 'booking_id', 'bookings');
  PERFORM _recreate_fk_cascade('reviews', 'booking_id', 'bookings');
  PERFORM _recreate_fk_cascade('reviews', 'cleaner_id', 'cleaners');
  PERFORM _recreate_fk_cascade('reviews', 'customer_id', 'customers');
  PERFORM _recreate_fk_cascade('booking_addons', 'booking_id', 'bookings');
  PERFORM _recreate_fk_cascade('payouts', 'cleaner_id', 'cleaners');
  PERFORM _recreate_fk_cascade('payouts', 'booking_id', 'bookings');
  PERFORM _recreate_fk_cascade('subscriptions', 'customer_id', 'customers');

  -- Cleaner-scoped data
  PERFORM _recreate_fk_cascade('cleaner_training_progress', 'cleaner_id', 'cleaners');
  PERFORM _recreate_fk_cascade('cleaner_quiz_attempts', 'cleaner_id', 'cleaners');
  PERFORM _recreate_fk_cascade('cleaner_insurance', 'cleaner_id', 'cleaners');
  PERFORM _recreate_fk_cascade('stripe_connected_accounts', 'cleaner_id', 'cleaners');
  PERFORM _recreate_fk_cascade('payout_ledger', 'cleaner_id', 'cleaners');
END$$;

DROP FUNCTION IF EXISTS _recreate_fk_cascade(regclass, text, regclass);

-- Non-PII deletion audit (proves a deletion happened; stores no personal data).
CREATE TABLE IF NOT EXISTS account_deletion_log (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email_hash  TEXT,                       -- sha256(email); never the raw email
  scope       TEXT NOT NULL,              -- 'pii' | 'account' | 'account_and_data'
  deleted_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ─────────────────────────────────────────────────────────────────────────
-- 032_legal_compliance_tracking.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Migration 032: legal compliance tracking.
--
-- Backend support for the legal-document audit: versioned legal documents,
-- per-user acceptance records, SMS/background-check/tax consents, privacy
-- requests, damage/incident claims, and cookie consents. All idempotent.

-- ── Legal documents (versioned registry) ─────────────────────────────────────
CREATE TABLE IF NOT EXISTS legal_documents (
  id             UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug           TEXT NOT NULL,
  title          TEXT NOT NULL,
  version        TEXT NOT NULL DEFAULT '1.0',
  effective_date DATE,
  last_updated   DATE,
  hash           TEXT,                       -- content hash of the published doc
  html_url       TEXT,
  pdf_url        TEXT,
  status         TEXT NOT NULL DEFAULT 'draft'
    CHECK (status IN ('draft','published','superseded','archived')),
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (slug, version)
);
CREATE INDEX IF NOT EXISTS idx_legal_documents_slug ON legal_documents (slug);

-- ── Legal acceptances (immutable consent records) ────────────────────────────
CREATE TABLE IF NOT EXISTS legal_acceptances (
  id                     UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id                UUID REFERENCES users(id) ON DELETE CASCADE,
  document_slug          TEXT NOT NULL,
  document_version       TEXT NOT NULL,
  document_hash          TEXT,
  accepted_at            TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  ip_address             TEXT,
  user_agent             TEXT,
  flow_context           TEXT,               -- e.g. customer_signup, checkout, cleaner_signup
  checkbox_label_snapshot TEXT
);
CREATE INDEX IF NOT EXISTS idx_legal_acceptances_user ON legal_acceptances (user_id);
CREATE INDEX IF NOT EXISTS idx_legal_acceptances_doc ON legal_acceptances (document_slug);

-- ── SMS consents (transactional vs marketing) ────────────────────────────────
CREATE TABLE IF NOT EXISTS sms_consents (
  id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id             UUID REFERENCES users(id) ON DELETE CASCADE,
  phone_number        TEXT NOT NULL,
  consent_type        TEXT NOT NULL DEFAULT 'transactional'
    CHECK (consent_type IN ('transactional','marketing')),
  opt_in_at           TIMESTAMPTZ,
  opt_in_source       TEXT,
  checkbox_text_snapshot TEXT,
  opt_out_at          TIMESTAMPTZ,
  opt_out_source      TEXT,
  last_stop_message_at TIMESTAMPTZ,
  created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_sms_consents_user ON sms_consents (user_id);

-- ── Background check consents (FCRA) ─────────────────────────────────────────
CREATE TABLE IF NOT EXISTS background_check_consents (
  id                    UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  cleaner_id            UUID REFERENCES cleaners(id) ON DELETE CASCADE,
  disclosure_version    TEXT,
  authorization_version TEXT,
  authorized_at         TIMESTAMPTZ,
  ip_address            TEXT,
  vendor                TEXT,
  report_status         TEXT,
  pre_adverse_action_at TIMESTAMPTZ,
  adverse_action_at     TIMESTAMPTZ,
  dispute_deadline      TIMESTAMPTZ,
  created_at            TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_bg_consents_cleaner ON background_check_consents (cleaner_id);

-- ── Tax profiles ─────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS tax_profiles (
  id                       UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  cleaner_id               UUID REFERENCES cleaners(id) ON DELETE CASCADE,
  legal_name               TEXT,
  business_name            TEXT,
  tin_status               TEXT DEFAULT 'not_collected',
  w9_collected_at          TIMESTAMPTZ,
  backup_withholding_status TEXT DEFAULT 'none',
  tax_form_delivery_consent BOOLEAN NOT NULL DEFAULT FALSE,
  tax_year                 INT,
  form_type                TEXT,             -- 1099-NEC | 1099-K | 1099-MISC
  form_status              TEXT,
  created_at               TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at               TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_tax_profiles_cleaner ON tax_profiles (cleaner_id);

-- ── Privacy requests (CCPA/GDPR DSARs) ───────────────────────────────────────
CREATE TABLE IF NOT EXISTS privacy_requests (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  requester_id  UUID REFERENCES users(id) ON DELETE SET NULL,
  request_type  TEXT NOT NULL
    CHECK (request_type IN ('know','access','delete','correct','opt_out','portability')),
  jurisdiction  TEXT,
  submitted_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  verified_at   TIMESTAMPTZ,
  due_at        TIMESTAMPTZ,
  status        TEXT NOT NULL DEFAULT 'received'
    CHECK (status IN ('received','verifying','in_progress','completed','denied')),
  response_at   TIMESTAMPTZ,
  denial_reason TEXT,
  appeal_status TEXT
);
CREATE INDEX IF NOT EXISTS idx_privacy_requests_requester ON privacy_requests (requester_id);

-- ── Damage claims ────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS damage_claims (
  id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  booking_id        UUID REFERENCES bookings(id) ON DELETE SET NULL,
  customer_id       UUID REFERENCES customers(id) ON DELETE SET NULL,
  cleaner_id        UUID REFERENCES cleaners(id) ON DELETE SET NULL,
  reported_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  deadline_status   TEXT,                    -- on_time | late
  description       TEXT,
  evidence_urls     JSONB NOT NULL DEFAULT '[]',
  cleaner_statement TEXT,
  decision          TEXT,                    -- repair | replace | credit | insurance | denied | pending
  payout_amount     INT,                     -- cents
  insurance_claim_id TEXT,
  status            TEXT NOT NULL DEFAULT 'open'
    CHECK (status IN ('open','investigating','resolved','denied')),
  created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_damage_claims_booking ON damage_claims (booking_id);

-- ── Incident reports (trust & safety) ────────────────────────────────────────
CREATE TABLE IF NOT EXISTS incident_reports (
  id                    UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  booking_id            UUID REFERENCES bookings(id) ON DELETE SET NULL,
  reporter_id           UUID REFERENCES users(id) ON DELETE SET NULL,
  type                  TEXT,
  severity              TEXT,
  description           TEXT,
  evidence_urls         JSONB NOT NULL DEFAULT '[]',
  police_report_required BOOLEAN NOT NULL DEFAULT FALSE,
  safety_action_taken   TEXT,
  status                TEXT NOT NULL DEFAULT 'open'
    CHECK (status IN ('open','investigating','resolved','closed')),
  created_at            TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_incident_reports_booking ON incident_reports (booking_id);

-- ── Cookie consents ──────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS cookie_consents (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id      UUID REFERENCES users(id) ON DELETE CASCADE,
  anonymous_id TEXT,
  necessary    BOOLEAN NOT NULL DEFAULT TRUE,
  functional   BOOLEAN NOT NULL DEFAULT FALSE,
  analytics    BOOLEAN NOT NULL DEFAULT FALSE,
  marketing    BOOLEAN NOT NULL DEFAULT FALSE,
  gpc_detected BOOLEAN NOT NULL DEFAULT FALSE,
  consent_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_cookie_consents_user ON cookie_consents (user_id);
CREATE INDEX IF NOT EXISTS idx_cookie_consents_anon ON cookie_consents (anonymous_id);

-- ─────────────────────────────────────────────────────────────────────────
-- 033_slack_integration.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Migration 033: Slack workspace integration.
--
-- Sweepr remains the source of truth. Slack is a notification/collaboration
-- interface. These tables store workspace connections (OAuth tokens), mapped
-- channels, OAuth CSRF state, and a posted-message registry so approval cards
-- can be updated in place.

-- ── Connected Slack workspaces ───────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS slack_workspaces (
  id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  team_id          TEXT NOT NULL UNIQUE,        -- Slack workspace (team) id
  team_name        TEXT,
  app_id           TEXT,
  bot_user_id      TEXT,
  bot_token        TEXT NOT NULL,               -- xoxb- token (secret)
  scope            TEXT,
  authed_user_id   TEXT,                         -- Slack user who installed
  installed_by     TEXT,                         -- Sweepr clerk id of installer
  incoming_webhook_url TEXT,                      -- optional, if requested
  status           TEXT NOT NULL DEFAULT 'active'
    CHECK (status IN ('active','revoked','error')),
  last_error       TEXT,
  created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ── Mapped Slack channels ────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS slack_channels (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  workspace_id UUID NOT NULL REFERENCES slack_workspaces(id) ON DELETE CASCADE,
  channel_id   TEXT NOT NULL,
  channel_name TEXT,
  -- Logical purpose this channel serves in Sweepr routing.
  purpose      TEXT NOT NULL DEFAULT 'custom'
    CHECK (purpose IN ('approvals','admin','operations','finance','it','training','custom')),
  is_private   BOOLEAN NOT NULL DEFAULT FALSE,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (workspace_id, channel_id)
);
CREATE INDEX IF NOT EXISTS idx_slack_channels_ws ON slack_channels (workspace_id);
CREATE INDEX IF NOT EXISTS idx_slack_channels_purpose ON slack_channels (purpose);

-- ── OAuth CSRF state (short-lived) ───────────────────────────────────────────
CREATE TABLE IF NOT EXISTS slack_oauth_states (
  state       TEXT PRIMARY KEY,
  created_by  TEXT,                              -- Sweepr clerk id
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  expires_at  TIMESTAMPTZ NOT NULL
);

-- ── Posted message registry (so cards can be updated in place) ───────────────
CREATE TABLE IF NOT EXISTS slack_messages (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  workspace_id UUID REFERENCES slack_workspaces(id) ON DELETE CASCADE,
  channel_id   TEXT NOT NULL,
  message_ts   TEXT NOT NULL,                    -- Slack message timestamp (id)
  ref_type     TEXT,                             -- e.g. 'fee_proposal', 'pricing_proposal'
  ref_id       TEXT,                             -- related Sweepr record id
  thread_ts    TEXT,                             -- collaboration thread root, if any
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_slack_messages_ref ON slack_messages (ref_type, ref_id);

-- ── Map Slack users to Sweepr users (for permission checks on actions) ───────
CREATE TABLE IF NOT EXISTS slack_user_links (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  workspace_id  UUID NOT NULL REFERENCES slack_workspaces(id) ON DELETE CASCADE,
  slack_user_id TEXT NOT NULL,
  user_id       UUID REFERENCES users(id) ON DELETE CASCADE,
  email         TEXT,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (workspace_id, slack_user_id)
);

-- ─────────────────────────────────────────────────────────────────────────
-- 034_fee_approval_engine.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Migration 034: Fee Change Approval Engine.
--
-- Versioned fee configurations plus a full proposal/approval state machine:
-- proposals, per-user actions, collaborators, notifications, and secure
-- single-use action links. Sweepr is the authoritative approval + audit system.

-- ── Versioned fee configurations ─────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS fee_configurations (
  id                 UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name               TEXT NOT NULL,
  fee_type           TEXT NOT NULL
    CHECK (fee_type IN ('customer_service_fee','platform_fee','cleaner_commission',
      'insurance_admin_fee','cancellation_fee','reschedule_fee','adjustment_fee',
      'marketplace_fee','payment_processing_pass_through','other')),
  affected_party     TEXT NOT NULL
    CHECK (affected_party IN ('customers','cleaners','both','internal_only')),
  calculation_method TEXT NOT NULL
    CHECK (calculation_method IN ('flat_amount','percentage','tiered_percentage',
      'dynamic_formula','market_based','city_based','service_type_based')),
  flat_amount_cents  INTEGER,
  percentage_bps     INTEGER,
  formula_json       JSONB,
  city               TEXT,
  state              TEXT,
  service_type       TEXT,
  status             TEXT NOT NULL DEFAULT 'draft'
    CHECK (status IN ('draft','pending_approval','active','superseded','archived')),
  active_from        TIMESTAMPTZ,
  active_until       TIMESTAMPTZ,
  version            INTEGER NOT NULL DEFAULT 1,
  supersedes_id      UUID REFERENCES fee_configurations(id),
  created_by         TEXT NOT NULL,                 -- clerk id
  created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at         TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fee_configs_status ON fee_configurations (status);

-- ── Proposals (the state machine) ────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS fee_change_proposals (
  id                        UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  proposed_fee_configuration_id UUID NOT NULL REFERENCES fee_configurations(id) ON DELETE CASCADE,
  proposer_clerk_id         TEXT NOT NULL,
  proposer_user_id          UUID REFERENCES users(id) ON DELETE SET NULL,
  title                     TEXT NOT NULL,
  reason                    TEXT NOT NULL,
  internal_notes            TEXT,
  external_notice_summary   TEXT,
  status                    TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN ('draft','pending','collaboration','approved','cooldown',
      'notice_scheduled','notice_sent','effective','declined','expired_declined',
      'cancelled','revoked')),
  proposed_effective_at     TIMESTAMPTZ NOT NULL,
  response_deadline_at      TIMESTAMPTZ NOT NULL,
  response_deadline_removed_at TIMESTAMPTZ,
  approved_at               TIMESTAMPTZ,
  cooldown_started_at       TIMESTAMPTZ,
  cooldown_expires_at       TIMESTAMPTZ,
  notice_sent_at            TIMESTAMPTZ,
  notice_period_ends_at     TIMESTAMPTZ,
  final_effective_at        TIMESTAMPTZ,
  declined_at               TIMESTAMPTZ,
  decline_reason            TEXT,
  created_at                TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at                TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fee_proposals_status ON fee_change_proposals (status);

-- ── Per-user actions (history) ───────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS fee_change_proposal_actions (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  proposal_id  UUID NOT NULL REFERENCES fee_change_proposals(id) ON DELETE CASCADE,
  actor_clerk_id TEXT NOT NULL,
  actor_email  TEXT,
  action       TEXT NOT NULL
    CHECK (action IN ('created','approved','declined','ignored','proposed_modification',
      'joined_collaboration','revoked_approval','modified','cooldown_started',
      'cooldown_reset','notice_sent','became_effective','expired_declined','cancelled')),
  comment      TEXT,
  proposed_modification_json JSONB,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fee_actions_proposal ON fee_change_proposal_actions (proposal_id);

-- ── Collaborators (required final approvers) ─────────────────────────────────
CREATE TABLE IF NOT EXISTS fee_change_collaborators (
  id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  proposal_id       UUID NOT NULL REFERENCES fee_change_proposals(id) ON DELETE CASCADE,
  clerk_id          TEXT NOT NULL,
  email             TEXT,
  joined_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  must_approve_final BOOLEAN NOT NULL DEFAULT TRUE,
  approved_final_at TIMESTAMPTZ,
  UNIQUE (proposal_id, clerk_id)
);

-- ── Notifications sent for a proposal ────────────────────────────────────────
CREATE TABLE IF NOT EXISTS fee_change_notifications (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  proposal_id  UUID NOT NULL REFERENCES fee_change_proposals(id) ON DELETE CASCADE,
  clerk_id     TEXT,
  channel      TEXT NOT NULL CHECK (channel IN ('in_app','email','slack','push','sms')),
  recipient    TEXT NOT NULL,
  status       TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN ('pending','sent','failed')),
  sent_at      TIMESTAMPTZ,
  provider_message_id TEXT,
  error_message TEXT,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fee_notifications_proposal ON fee_change_notifications (proposal_id);

-- ── Secure single-use action links (email fallback) ──────────────────────────
CREATE TABLE IF NOT EXISTS fee_change_action_links (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  proposal_id UUID NOT NULL REFERENCES fee_change_proposals(id) ON DELETE CASCADE,
  clerk_id    TEXT NOT NULL,
  email       TEXT,
  token_hash  TEXT NOT NULL,               -- sha256 of the raw token; raw never stored
  expires_at  TIMESTAMPTZ NOT NULL,
  used_at     TIMESTAMPTZ,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fee_action_links_token ON fee_change_action_links (token_hash);

-- ─────────────────────────────────────────────────────────────────────────
-- 035_slack_user_tokens.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Migration 035: per-user Slack tokens for the embedded workspace.
--
-- The embedded Slack tab renders each admin's *own* Slack view, so we store a
-- user OAuth token (xoxp-) per linked Slack account. Slack permissions are
-- enforced by Slack (the token only sees what that user can see); Sweepr
-- permissions are enforced separately at the route layer.

ALTER TABLE slack_user_links
  ADD COLUMN IF NOT EXISTS user_token   TEXT,
  ADD COLUMN IF NOT EXISTS user_scopes  TEXT,
  ADD COLUMN IF NOT EXISTS connected_at TIMESTAMPTZ;

-- Distinguish bot-install OAuth from personal-connect OAuth on the same callback.
ALTER TABLE slack_oauth_states
  ADD COLUMN IF NOT EXISTS kind TEXT NOT NULL DEFAULT 'install';

-- ─────────────────────────────────────────────────────────────────────────
-- 036_pricing_engine.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Migration 036: Algorithmic Cleaning Pricing.
--
-- Versioned pricing rules, add-ons, stored quotes, and a pricing-change approval
-- flow (parallel to the fee approval engine but kept separate for clarity).
-- Bookings store the exact pricing rule version + quote snapshot used.

-- ── Versioned pricing rules ──────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS pricing_rules (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  description TEXT,
  market_city TEXT,
  market_state TEXT,
  market_zip TEXT,
  status TEXT NOT NULL DEFAULT 'draft'
    CHECK (status IN ('draft','pending_approval','active','superseded','archived')),
  currency TEXT NOT NULL DEFAULT 'USD',

  base_fee_cents INTEGER NOT NULL DEFAULT 0,
  minimum_booking_price_cents INTEGER NOT NULL DEFAULT 0,
  maximum_booking_price_cents INTEGER,

  sqft_pricing_enabled BOOLEAN NOT NULL DEFAULT TRUE,
  sqft_included_in_base INTEGER DEFAULT 750,
  sqft_tiers_json JSONB,                 -- [{ "max": 1000, "add_cents": 2000 }, ...]
  sqft_overage_rate_cents_per_sqft INTEGER,
  sqft_custom_quote_threshold INTEGER,

  bedrooms_included_in_base INTEGER DEFAULT 1,
  price_per_extra_bedroom_cents INTEGER DEFAULT 0,
  bedroom_tiers_json JSONB,

  bathrooms_included_in_base NUMERIC DEFAULT 1,
  price_per_extra_bathroom_cents INTEGER DEFAULT 0,
  half_bathroom_price_cents INTEGER DEFAULT 0,
  bathroom_tiers_json JSONB,

  distance_pricing_enabled BOOLEAN NOT NULL DEFAULT FALSE,
  free_distance_miles NUMERIC DEFAULT 0,
  price_per_mile_cents INTEGER DEFAULT 0,
  distance_calculation_origin TEXT,
  maximum_service_distance_miles NUMERIC,
  long_distance_surcharge_cents INTEGER,

  property_type_adjustments_json JSONB,   -- { "apartment": 0, "townhouse": 500, ... } (bps or cents? -> bps)
  service_type_multiplier_json JSONB,     -- { "standard": 100, "deep": 145, ... } (percent x100)
  service_type_fixed_surcharge_json JSONB,
  intensity_multiplier_json JSONB,        -- { "light": 90, "normal": 100, ... }

  pet_pricing_enabled BOOLEAN NOT NULL DEFAULT FALSE,
  pet_base_fee_cents INTEGER DEFAULT 0,
  price_per_pet_cents INTEGER DEFAULT 0,
  max_pet_count_before_custom_quote INTEGER,

  urgency_pricing_enabled BOOLEAN NOT NULL DEFAULT FALSE,
  urgency_rules_json JSONB,               -- { "same_day": 120, "next_day": 110, ... } (percent x100)

  recurring_discount_enabled BOOLEAN NOT NULL DEFAULT FALSE,
  recurring_discount_json JSONB,          -- { "weekly_bps": 1500, "biweekly_bps": 1000, "monthly_bps": 500 }

  rounding_enabled BOOLEAN NOT NULL DEFAULT TRUE,
  rounding_strategy TEXT DEFAULT 'end_in_9',
  rounding_increment_cents INTEGER DEFAULT 1000,
  rounding_ending_cents INTEGER DEFAULT 900,

  maximum_auto_quote_price_cents INTEGER,
  requires_custom_quote_above_cents INTEGER,
  max_discount_bps INTEGER,
  max_dynamic_adjustment_bps INTEGER,

  active_from TIMESTAMPTZ,
  active_until TIMESTAMPTZ,
  version INTEGER NOT NULL DEFAULT 1,
  supersedes_rule_id UUID REFERENCES pricing_rules(id),
  created_by TEXT NOT NULL,
  approved_proposal_id UUID,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_pricing_rules_status ON pricing_rules (status);

-- ── Add-ons (versioned with the rule) ────────────────────────────────────────
CREATE TABLE IF NOT EXISTS pricing_addons (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  pricing_rule_id UUID REFERENCES pricing_rules(id) ON DELETE CASCADE,
  addon_key TEXT NOT NULL,
  addon_name TEXT NOT NULL,
  addon_description TEXT,
  price_cents INTEGER NOT NULL DEFAULT 0,
  estimated_minutes INTEGER,
  cleaner_payout_adjustment_cents INTEGER,
  requires_customer_disclosure BOOLEAN NOT NULL DEFAULT FALSE,
  requires_cleaner_acknowledgement BOOLEAN NOT NULL DEFAULT FALSE,
  is_active BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_pricing_addons_rule ON pricing_addons (pricing_rule_id);

-- ── Stored quotes (snapshot used by a booking) ───────────────────────────────
CREATE TABLE IF NOT EXISTS pricing_quotes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  customer_id UUID,
  booking_id UUID,
  pricing_rule_id UUID NOT NULL REFERENCES pricing_rules(id),
  pricing_rule_version INTEGER NOT NULL,
  quote_input_json JSONB NOT NULL,
  quote_output_json JSONB NOT NULL,
  customer_total_cents INTEGER NOT NULL,
  estimated_cleaner_payout_cents INTEGER,
  estimated_platform_revenue_cents INTEGER,
  requires_custom_quote BOOLEAN NOT NULL DEFAULT FALSE,
  expires_at TIMESTAMPTZ,
  accepted_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_pricing_quotes_booking ON pricing_quotes (booking_id);

-- ── Pricing change proposals (approval workflow) ─────────────────────────────
CREATE TABLE IF NOT EXISTS pricing_change_proposals (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  proposed_pricing_rule_id UUID NOT NULL REFERENCES pricing_rules(id) ON DELETE CASCADE,
  proposer_clerk_id TEXT NOT NULL,
  proposer_user_id UUID REFERENCES users(id) ON DELETE SET NULL,
  title TEXT NOT NULL,
  reason TEXT NOT NULL,
  internal_notes TEXT,
  external_notice_summary TEXT,
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN ('draft','pending','collaboration','approved','cooldown',
      'notice_scheduled','notice_sent','effective','declined','expired_declined',
      'cancelled','revoked')),
  proposed_effective_at TIMESTAMPTZ NOT NULL,
  response_deadline_at TIMESTAMPTZ NOT NULL,
  response_deadline_removed_at TIMESTAMPTZ,
  approved_at TIMESTAMPTZ,
  cooldown_started_at TIMESTAMPTZ,
  cooldown_expires_at TIMESTAMPTZ,
  notice_sent_at TIMESTAMPTZ,
  notice_period_ends_at TIMESTAMPTZ,
  final_effective_at TIMESTAMPTZ,
  declined_at TIMESTAMPTZ,
  decline_reason TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_pricing_proposals_status ON pricing_change_proposals (status);

CREATE TABLE IF NOT EXISTS pricing_change_actions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  proposal_id UUID NOT NULL REFERENCES pricing_change_proposals(id) ON DELETE CASCADE,
  actor_clerk_id TEXT NOT NULL,
  actor_email TEXT,
  action TEXT NOT NULL,
  comment TEXT,
  proposed_modification_json JSONB,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_pricing_actions_proposal ON pricing_change_actions (proposal_id);

CREATE TABLE IF NOT EXISTS pricing_change_collaborators (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  proposal_id UUID NOT NULL REFERENCES pricing_change_proposals(id) ON DELETE CASCADE,
  clerk_id TEXT NOT NULL,
  email TEXT,
  joined_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  must_approve_final BOOLEAN NOT NULL DEFAULT TRUE,
  approved_final_at TIMESTAMPTZ,
  UNIQUE (proposal_id, clerk_id)
);

-- ── Booking quote snapshot columns ───────────────────────────────────────────
ALTER TABLE bookings
  ADD COLUMN IF NOT EXISTS pricing_quote_id UUID,
  ADD COLUMN IF NOT EXISTS pricing_rule_id UUID,
  ADD COLUMN IF NOT EXISTS pricing_rule_version INTEGER,
  ADD COLUMN IF NOT EXISTS pricing_line_items_json JSONB,
  ADD COLUMN IF NOT EXISTS estimated_cleaner_payout_cents INTEGER;

-- ─────────────────────────────────────────────────────────────────────────
-- 037_security_tickets.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Migration 037: Security inbox (inbound email → tickets) + replies.
--
-- security@getsweepr.com inbound mail (via MailerSend inbound route) creates a
-- ticket with a unique SEC-YYYY-NNNNNN number; an auto-reply is sent and logged.
-- Admins reply from the Security console; replies thread back to the reporter.

CREATE TABLE IF NOT EXISTS security_tickets (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  seq             BIGSERIAL,                       -- numbering source
  ticket_number   TEXT UNIQUE,                     -- SEC-YYYY-NNNNNN
  sender_email    TEXT NOT NULL,
  sender_name     TEXT,
  sender_ip       TEXT,
  subject         TEXT,
  classification  TEXT NOT NULL DEFAULT 'General Inquiry',
  status          TEXT NOT NULL DEFAULT 'Active'
    CHECK (status IN ('Active','Pending Review','Awaiting Response','Investigating',
      'Information Requested','Resolved','Closed','Rejected','Duplicate','Unable to Reproduce')),
  case_owner      TEXT,
  assigned_to     TEXT,
  inbound_message_id  TEXT,
  received_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  auto_reply_sent_at  TIMESTAMPTZ,
  last_reply_at   TIMESTAMPTZ,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_security_tickets_status ON security_tickets (status);
CREATE INDEX IF NOT EXISTS idx_security_tickets_received ON security_tickets (received_at DESC);

CREATE TABLE IF NOT EXISTS security_ticket_messages (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  ticket_id    UUID NOT NULL REFERENCES security_tickets(id) ON DELETE CASCADE,
  direction    TEXT NOT NULL CHECK (direction IN ('inbound','outbound','auto_reply')),
  from_email   TEXT,
  to_email     TEXT,
  subject      TEXT,
  body         TEXT,
  message_id   TEXT,
  delivery_status TEXT,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_security_messages_ticket ON security_ticket_messages (ticket_id);

-- ─────────────────────────────────────────────────────────────────────────
-- 038_compact_ticket_ids.sql
-- ─────────────────────────────────────────────────────────────────────────
-- Migration 038: compact ticket identifiers for security + IT tickets.
--
-- Two identifiers per ticket:
--   • case_code  — public-facing Case Code (PREFIX_HEX5), shown to users.
--   • ticket_id  — internal canonical Ticket ID (PREFIX_DATE:TIME.TYPE_HEX).
-- Plus decoded parts for sorting/search. Legacy ticket_number kept for back-compat.

ALTER TABLE security_tickets
  ADD COLUMN IF NOT EXISTS ticket_id      TEXT,
  ADD COLUMN IF NOT EXISTS case_code      TEXT,
  ADD COLUMN IF NOT EXISTS ticket_prefix  TEXT,
  ADD COLUMN IF NOT EXISTS encoded_date   TEXT,
  ADD COLUMN IF NOT EXISTS encoded_time   TEXT,
  ADD COLUMN IF NOT EXISTS issue_type     TEXT,
  ADD COLUMN IF NOT EXISTS hex_suffix     TEXT;
CREATE INDEX IF NOT EXISTS idx_security_tickets_case ON security_tickets (case_code);
CREATE INDEX IF NOT EXISTS idx_security_tickets_ticketid ON security_tickets (ticket_id);

ALTER TABLE it_tickets
  ADD COLUMN IF NOT EXISTS ticket_id      TEXT,
  ADD COLUMN IF NOT EXISTS case_code      TEXT,
  ADD COLUMN IF NOT EXISTS ticket_prefix  TEXT,
  ADD COLUMN IF NOT EXISTS encoded_date   TEXT,
  ADD COLUMN IF NOT EXISTS encoded_time   TEXT,
  ADD COLUMN IF NOT EXISTS issue_type     TEXT,
  ADD COLUMN IF NOT EXISTS hex_suffix     TEXT;
CREATE INDEX IF NOT EXISTS idx_it_tickets_case ON it_tickets (case_code);
CREATE INDEX IF NOT EXISTS idx_it_tickets_ticketid ON it_tickets (ticket_id);
